"""Local autogenerated benchmark and test artifact directory."""

from pathlib import Path

REPO_ROOT = Path(__file__).resolve().parents[1]
AUTOGEN_DIR = REPO_ROOT / "temp-alkahest" / "testing" / "autogen"


def autogen_path(name: str) -> Path:
    """Return ``AUTOGEN_DIR / name``, creating parent directories."""
    path = AUTOGEN_DIR / name
    path.parent.mkdir(parents=True, exist_ok=True)
    return path
